var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"큭…!","JPN":"くっ……！","ENG":"Khh...!","TWN":"咳……！"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"도망칠 곳도 없고, 최악이네.","JPN":"逃げ場もないし、最悪。","ENG":"This is the worst. I've got nowhere to run.","TWN":"無處可逃，太糟糕了。"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐야? 어디가?","JPN":"ん？　どこ行くんだ？","ENG":"Huh? Where do you think you're going?","TWN":"怎麼回事？你去哪？"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"날 처리하러 온 거 아니었어?","JPN":"あたしを始末しに来たんじゃないの？","ENG":"Aren't you here to kill me?","TWN":"不是來殺我的嗎？"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"무슨 소린지 하나도 못 알아듣겠군.","JPN":"さっきから何を言ってるんだ？","ENG":"I have no idea what you're talking about.","TWN":"我完全聽不懂你在說什麼。"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"넌 분명 리플레이서 놈들이 활개칠 때 죽었던 게 아니었나?","JPN":"貴様は確か、リプレイサーの奴らが暴れていた時に死んだのではなかったのか？","ENG":"I thought you died when those Replacers ran amok.","TWN":"你在克隆集團那一次事件中不是早就死了嗎？"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐…? 거기서부터 아무것도 몰랐다고?","JPN":"は……？　あの後のこと、何も知らないの？","ENG":"What...? That's the last thing you know?","TWN":"什麼……？你對那以後的事情毫不知情？"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래, 네 녀석이 나유빈과 어울리고 다녔다는 얘기도 처음 듣는다.","JPN":"ああ、貴様がイチノセ・カオルと付き合っていたという話も初耳だ。","ENG":"Yes. And this is the first time I'm hearing that you were hanging out with Na Yubin.","TWN":"沒錯，我還第一次聽說了你和羅瑜斌一起行動。"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그리고 클리포트게임이 한 차례 끝난 이상, 육익이든 범죄자든 내가 널 당장 처리할 의무 같은 건 없어.","JPN":"それから、クリフォトゲームが一度終わった以上、六翼だろうが犯罪者だろうが私が今すぐ貴様を始末する理由はない。","ENG":"Furthermore, since the Qliphoth Game is already done with, I have no obligation to get rid of you right away, even if you're Six Wings or a criminal.","TWN":"既然逆卡巴拉遊戲已經告一段落，我現在也沒有義務殺掉你，不管你是六翼還是囚犯。"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어…….","JPN":"えっ……？","ENG":"Oh...","TWN":"喔……"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"살아있는 건 둘째 치고, 그 녀석이 지금 네 꼬라지를 보면 적잖이 충격을 받겠어.","JPN":"あいつが今の貴様の姿を見ればショックを受けるだろうな。","ENG":"Aside from being alive, that kid would be shocked if she could see you right now.","TWN":"先不說你還活著，如果她看到你現在這副樣子一定會很受打擊吧。"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이곳 중죄수들은 너처럼 흉물스런 옷을 입고 다니는 형벌이라도 받는 건가?","JPN":"ここの重罪人は、みんな貴様のような醜い服を着る刑罰でも受けているのか？","ENG":"Is it the felons' punishment to wear something so hideous?","TWN":"這裡的其他重犯也要和你一樣穿上如此奇怪的衣服嗎？"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"패션이거든?","JPN":"ファッションだよ。わからない？","ENG":"It's called fashion.","TWN":"這可是時尚，懂嗎？"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"하아… 적이 아니라는 건 미리 좀 알려주면 좋았잖아.","JPN":"はあ……敵じゃないなら先に言ってよね。","ENG":"*Sigh...* You could've told me you weren't an enemy.","TWN":"唉……怎麼不早點告訴我不是敵人。"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다짜고짜 덤벼 놓고 뻔뻔하군.","JPN":"かかってきたのは貴様だろう。","ENG":"You're the one who jumped at me.","TWN":"明明是你先出手的，真是厚臉皮。"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};